script.body:
param([string]$Path = '.', [int]$MinSizeMB = 1)
$files = Get-ChildItem -Path $Path -Recurse -File -ErrorAction SilentlyContinue |
    Where-Object { $_.Length -gt ($MinSizeMB * 1MB) }
$hashes = @{}
foreach ($file in $files) {
    $hash = (Get-FileHash -Path $file.FullName -Algorithm MD5).Hash
    if (-not $hashes.ContainsKey($hash)) {
        $hashes[$hash] = @()
    }
    $hashes[$hash] += $file
}
$duplicates = $hashes.GetEnumerator() | Where-Object { $_.Value.Count -gt 1 }
if ($duplicates) {
    foreach ($dup in $duplicates) {
        Write-Output "=== Duplicates (Hash: $($dup.Key.Substring(0,8))...) ==="
        $dup.Value | ForEach-Object {
            Write-Output "  $($_.FullName) ({0:N2} MB)" -f ($_.Length/1MB)
        }
        Write-Output ''
    }
} else {
    Write-Output 'No duplicate files found.'
}
